import './Design.css'

function About() {
  return (
    <div className='contain-about'>
      {/* <div className='about'> */}
        <h3 className='about-h'> About Me</h3>
        <p className='about-para'>Hello there! My name is Anand Agarwal. I am a Post Grad Student @ TJC, and I'm very passionate about Full Stack development and Web designing.<br/>

I am dedicated, and have acquired the skills and knowledge necessary to make a project a success.<br/>

I get across to people and adjust to changes with ease. I believe that a person should work on developing their professional skills and learning new things all the time.</p>
      {/* </div> */}
    </div>
  )
}

export default About
